// ── PWA INSTALL ──────────────────────────────────────────────
window.addEventListener('beforeinstallprompt', e => {
  e.preventDefault();
  APP.deferredPrompt = e;
  // Only show if not already installed
  if (window.matchMedia('(display-mode: standalone)').matches) return;
  const banner = document.getElementById('installBanner');
  if (banner) banner.classList.add('show');
});

// Detect installed (standalone mode) — hide banner
window.addEventListener('appinstalled', () => {
  APP.deferredPrompt = null;
  const banner = document.getElementById('installBanner');
  if (banner) banner.classList.remove('show');
  toast('FuelBunk Pro installed! 🎉', 'success');
});

function installPWA() {
  if (APP.deferredPrompt) {
    // Android / Chrome
    APP.deferredPrompt.prompt();
    APP.deferredPrompt.userChoice.then(choice => {
      if (choice.outcome === 'accepted') toast('Installing FuelBunk Pro…', 'success');
      APP.deferredPrompt = null;
      document.getElementById('installBanner').classList.remove('show');
    });
  } else {
    // iOS Safari — show manual instructions
    const isIOS = /iphone|ipad|ipod/i.test(navigator.userAgent);
    if (isIOS) {
      toast('Tap Share → "Add to Home Screen" to install on iOS', 'info');
    } else {
      toast('Open in Chrome or Edge to install', 'info');
    }
  }
}
function dismissInstall() {
  document.getElementById('installBanner').classList.remove('show');
  // Remember dismissal for 7 days
  try { localStorage.setItem('installDismissed', Date.now()); } catch(e) {}
}

// Show banner on iOS if not standalone (iOS never fires beforeinstallprompt)
(function checkIOSInstall() {
  const isIOS = /iphone|ipad|ipod/i.test(navigator.userAgent);
  const isStandalone = window.navigator.standalone === true || window.matchMedia('(display-mode: standalone)').matches;
  if (isIOS && !isStandalone) {
    try {
      const dismissed = parseInt(localStorage.getItem('installDismissed') || '0');
      if (Date.now() - dismissed < 7 * 24 * 3600 * 1000) return; // snoozed
    } catch(e) {}
    setTimeout(() => {
      const banner = document.getElementById('installBanner');
      if (banner) banner.classList.add('show');
    }, 3000);
  }
})();

// ── ONLINE/OFFLINE ───────────────────────────────────────────
function updateOnlineStatus() {
  const online = navigator.onLine;
  document.body.classList.toggle('is-offline', !online);
  const pill = document.getElementById('statusPill');
  const queuePill = document.getElementById('offlineQueuePill');
  const qLen = typeof offlineQueueSize === 'function' ? offlineQueueSize() : 0;
  if (pill) {
    pill.className = `status-pill ${online ? 'online' : 'offline'}`;
    pill.querySelector('.status-text').textContent = online ? 'Online' : 'Offline';
  }
  if (queuePill) {
    queuePill.style.display = qLen > 0 ? 'flex' : 'none';
    const cntEl = document.getElementById('offlineQueueCount');
    if (cntEl) cntEl.textContent = qLen;
  }
  if (online) {
    if ('serviceWorker' in navigator && 'SyncManager' in window) {
      navigator.serviceWorker.ready.then(reg => reg.sync.register('sync-sales')).catch(() => {});
    }
    if (typeof flushOfflineQueue === 'function' && qLen > 0) {
      setTimeout(flushOfflineQueue, 800);
    }
  }
}
window.addEventListener('online', updateOnlineStatus);
window.addEventListener('offline', updateOnlineStatus);

// ── INIT ─────────────────────────────────────────────────────
function _splashProgress(pct, msg) {
  try {
    var f = document.getElementById('splash-bar-fill');
    var m = document.getElementById('splash-msg');
    if (f) f.style.width = pct + '%';
    if (m && msg) m.textContent = msg;
  } catch(e) {}
}

async function initApp() {
  _splashProgress(70, 'Initializing...');
  // Local file guard removed for standalone build

  // Check if a tenant is selected — if not, show selector screen
  _splashProgress(80, 'Loading station...');
  const _tenant = mt_getActiveTenant();
  if (!_tenant) {
    document.body.classList.add('app-ready');
    await mt_showSelector();
    return;
  }

  // Store tenant info in APP for use throughout
  APP.tenant = _tenant;
  // Only show super-admin-only pages if user entered via super admin compare flow
  // (not just because super session cookie exists from a previous login)
  if (window._superAdminCompareMode === true) APP.isSuperAdmin = true;

  // HTTPS redirect: REMOVED for standalone HTML build

  // Set SEED data IMMEDIATELY so app always works
  APP.data = JSON.parse(JSON.stringify(SEED));
  APP.auditLog = [];

  // Listen for SW messages (sync complete, update available)
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.addEventListener('message', e => {
      if (e.data?.type === 'SYNC_COMPLETE') toast('Data synced!', 'info');
      if (e.data?.type === 'UPDATE_AVAILABLE') toast('App updated — reload for latest version', 'info');
      // FIX 19a: SW background-sync asks client to flush its offline queue
      if (e.data?.type === 'SYNC_REQUESTED') {
        if (typeof flushOfflineQueue === 'function') {
          flushOfflineQueue().catch(() => {});
        }
      }
      // FIX 19b: Push notification click navigates to a specific page within the SPA
      if (e.data?.type === 'NOTIFICATION_NAVIGATE' && e.data?.url) {
        const hash = new URL(e.data.url, location.origin).hash;
        if (hash && hash.startsWith('#')) {
          const page = hash.slice(1);
          if (page && typeof renderPage === 'function') {
            APP.page = page;
            renderPage();
          }
        }
      }
    });
  }

  // Clock + status
  updateClock(); setInterval(updateClock, 1000); updateOnlineStatus();

  // Cross-tab sync: admin auto-refreshes tanks when employee submits in another tab
  try {
    var syncCh = new BroadcastChannel('fuelbunk_sync');
    syncCh.onmessage = function(evt) {
      if (!evt.data || evt.data.type !== 'EMP_SUBMITTED') return;
      Promise.all([db.getAll('tanks'), db.getAll('pumps'), db.getAll('sales')]).then(function(res) {
        var freshTanks = res[0], freshPumps = res[1], freshSales = res[2];
        if (freshTanks.length && APP.data) {
          APP.data.tanks = freshTanks.map(_normTank);
          APP.data.pumps = freshPumps.map(_normPump);
          if (freshSales.length) APP.data.sales = freshSales.sort(function(a,b){ return b.id - a.id; });
        }
        if (APP.role === 'admin') {
          var name = evt.data.employee || 'Employee';
          var ded = evt.data.deductions || {};
          var parts = Object.keys(ded).map(function(ft){ return getFuel(ft).short + ': ' + fmt(ded[ft]) + 'L'; });
          toast(name + ' submitted' + (parts.length ? ' — ' + parts.join(', ') + ' deducted' : ''), 'info');
          if (APP.page === 'tanks' || APP.page === 'dashboard') renderPage();
        }
      }).catch(function(){});
    };
  } catch(e) {}

  // Idle timer
  ['click','keydown','touchstart','scroll'].forEach(evt =>
    document.addEventListener(evt, resetIdleTimer, { passive: true })
  );

  _splashProgress(85, 'Checking session...');
  // Check session
  var sessionOk = loadSession();

  if (sessionOk) {
    if (APP.role === 'employee') { emp_loadSession(); if (!empState.active) { empState.page = 'login'; } }
    // Load data WITH token now set by loadSession — ensures correct server data on every refresh
    try {
      await Promise.race([
        loadData(),
        new Promise((_, rej) => setTimeout(() => rej(new Error('DB timeout 5s')), 5000))
      ]);
      // Snapshot data for offline use
      if (typeof saveDataSnapshot === 'function' && APP.data) saveDataSnapshot(APP.data);
    } catch (e) {
      console.warn('DB load failed:', e.message);
      // Offline fallback — restore from last snapshot
      if (!navigator.onLine && typeof loadDataSnapshot === 'function') {
        const snap = loadDataSnapshot();
        if (snap) {
          APP.data = snap;
          console.log('[Offline] Restored data from snapshot');
          // FIX F-04: Show stale warning if snapshot is older than 24h
          if (window._snapshotIsStale && window._snapshotAgeHours) {
            if (typeof toast === 'function') toast('📴 Offline — showing data from ' + window._snapshotAgeHours + 'h ago. Prices may be outdated.', 'warning');
            // Show persistent stale banner in the offline bar
            const bar = document.getElementById('offlineBar');
            if (bar) {
              bar.textContent = '⚡ Offline — showing data from ' + window._snapshotAgeHours + 'h ago. Fuel prices may be stale.';
              bar.style.display = 'block';
              bar.style.background = '#78350f';
              bar.style.color = '#f97316';
            }
          } else {
            if (typeof toast === 'function') toast('📴 Offline — showing last saved data', 'info');
          }
        }
      }
    }
    // ── Shift Manager session restore: employee token can't access /api/data/employees
    // so loadData() returns empty arrays. Fetch staff-data explicitly before rendering.
    if (APP.role === 'employee' && empState.active && empState.user?.role === 'Shift Manager') {
      if (typeof _fetchMgrData === 'function') {
        try { await _fetchMgrData(); } catch(e) { console.warn('[initApp] Shift Manager data fetch failed:', e.message); }
      }
    }
    enterApp();
  } else {
    showLoginScreen();
  }
  _splashProgress(100, 'Ready!');
  document.body.classList.add('app-ready');

  // Load audit log AFTER app is visible (non-blocking, with timeout)
  setTimeout(async () => {
    try {
      if (db && db.db) {
        var logs = await Promise.race([
          db.getAll('auditLog'),
          new Promise((_, rej) => setTimeout(() => rej('timeout'), 2000))
        ]);
        APP.auditLog = logs || [];
        APP.auditLog.sort((a,b) => (b.timestamp||'').localeCompare(a.timestamp||''));
      }
    } catch { APP.auditLog = []; }
  }, 1000);

  setTimeout(() => { if (APP.data) { checkTankAlerts(APP.data.tanks); checkCreditAlerts(APP.data.creditCustomers); } }, 5000);
}

// ── Admin User Management (Tenant level) ──
// ── ADMIN/EMPLOYEE PASSWORD RESET ────────────────────────
function openChangeMyPasswordModal() {
  openModal('🔑 Change My Password',
    `<div class="form-group"><label class="form-label">Current Password *</label>
       <input class="form-input" id="curPass" type="password" placeholder="Enter current password" autocomplete="current-password" />
     </div>
     <div class="form-group"><label class="form-label">New Password *</label>
       <input class="form-input" id="newPass" type="password" placeholder="Min 6 characters" autocomplete="new-password" />
     </div>
     <div class="form-group"><label class="form-label">Confirm New Password *</label>
       <input class="form-input" id="confPass" type="password" placeholder="Re-enter new password" />
     </div>`,
    `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
     <button class="btn btn-accent" onclick="saveMyPassword()">🔑 Update Password</button>`
  );
}

async function saveMyPassword() {
  const curPass = document.getElementById('curPass')?.value || '';
  const newPass = document.getElementById('newPass')?.value || '';
  const confPass = document.getElementById('confPass')?.value || '';
  if (!curPass) { toast('Enter current password', 'error'); return; }
  if (!newPass || newPass.length < 6) { toast('New password must be at least 6 characters', 'error'); return; }
  if (newPass !== confPass) { toast('Passwords do not match', 'error'); return; }
  try {
    // Try API call first (bridge.js overrides this for server auth)
    if (typeof AuthAPI !== 'undefined') {
      await AuthAPI.changePassword(newPass);
      closeModal();
      toast('Password updated successfully', 'success');
    } else {
      toast('Password change not available in offline mode', 'error');
    }
  } catch(e) {
    toast(e.message || 'Failed to update password', 'error');
  }
}

function openResetEmployeePasswordModal(empId) {
  const emp = APP.data.employees.find(e => parseInt(e.id) === parseInt(empId));
  if (!emp) return;
  openModal(`🔑 Reset PIN — ${sanitize(emp.name)}`,
    `<div style="margin-bottom:12px;font-size:12px;color:var(--text-2);padding:10px;background:var(--bg-0);border-radius:8px">
       Reset the 4-digit login PIN for <strong style="color:var(--accent-light)">${sanitize(emp.name)}</strong>.
     </div>
     <div class="form-group"><label class="form-label">New 4-Digit PIN *</label>
       <input class="form-input mono" id="newEmpPIN" type="password" inputmode="numeric" maxlength="4" placeholder="••••" style="font-size:24px;letter-spacing:8px;text-align:center" />
     </div>
     <div class="form-group"><label class="form-label">Confirm PIN *</label>
       <input class="form-input mono" id="confEmpPIN" type="password" inputmode="numeric" maxlength="4" placeholder="••••" style="font-size:24px;letter-spacing:8px;text-align:center" />
     </div>
     <input type="hidden" id="resetEmpId" value="${empId}" />`,
    `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
     <button class="btn btn-accent" onclick="doResetEmployeePin()">🔑 Reset PIN</button>`
  );
  // Fix (e): auto-focus the new PIN input
  requestAnimationFrame(() => { const el = document.getElementById('newEmpPIN'); if (el) el.focus(); });
}

async function doResetEmployeePin() {
  const empId = parseInt(document.getElementById('resetEmpId')?.value);
  const pin = document.getElementById('newEmpPIN')?.value?.trim();
  const conf = document.getElementById('confEmpPIN')?.value?.trim();
  if (!pin || pin.length !== 4 || !/^\d{4}$/.test(pin)) { toast('PIN must be exactly 4 digits', 'error'); return; }
  if (pin !== conf) { toast('PINs do not match', 'error'); return; }
  const emp = APP.data.employees.find(e => parseInt(e.id) === parseInt(empId));
  if (!emp) { toast('Employee not found', 'error'); return; }
  try {
    const hash = await sha256(pin);
    emp.pinHash = hash;
    // FIX BUG-08: Write only to the server (PostgreSQL via REST). Removed the duplicate
    // localStorage saveEmpPins() write which diverged from the server after any reload
    // and could allow employee login with an old PIN while offline.
    await db.put('employees', emp);
    closeModal();
    toast(`PIN reset for ${emp.name}`, 'success');
    renderPage();
  } catch(e) {
    toast('Failed to reset PIN: ' + (e.message||e), 'error');
  }
}

function openChangeAdminPassModal(userIdx) {
  const t = mt_getActiveTenant();
  if (!t) return;
  const u = (t.adminUsers||[])[userIdx];
  if (!u) return;
  openModal(`🔑 Change Password — ${sanitize(u.name)}`,
    `<input type="hidden" id="adminUserIdx" value="${userIdx}" />
     <div class="form-group"><label class="form-label">New Password *</label>
       <input class="form-input" id="newAdminPass" type="password" placeholder="Enter new password" autocomplete="new-password" />
     </div>
     <div class="form-group"><label class="form-label">Confirm Password *</label>
       <input class="form-input" id="confirmAdminPass" type="password" placeholder="Confirm password" />
     </div>`,
    `<button class="btn btn-ghost" onclick="closeModal()">Cancel</button>
     <button class="btn btn-accent" onclick="saveAdminPassword()">🔑 Update Password</button>`
  );
}

async function saveAdminPassword() {
  const idx  = parseInt(document.getElementById('adminUserIdx')?.value);
  const pass = document.getElementById('newAdminPass')?.value;
  const conf = document.getElementById('confirmAdminPass')?.value;
  if (!pass || pass.length < 6) { toast('Password must be at least 6 characters', 'error'); return; }
  if (pass !== conf) { toast('Passwords do not match', 'error'); return; }
  const buf = await crypto.subtle.digest('SHA-256', new TextEncoder().encode(pass));
  const hash = Array.from(new Uint8Array(buf)).map(b=>b.toString(16).padStart(2,'0')).join('');
  const tenants = mt_getTenants();
  const tIdx = tenants.findIndex(t => t.id === APP.tenant?.id);
  if (tIdx === -1) { toast('Tenant not found', 'error'); return; }
  tenants[tIdx].adminUsers[idx].passHash = hash;
  mt_saveTenants(tenants);
  mt_setActiveTenant(tenants[tIdx]);
  // FIX INFO-02: Guard ADMIN_USERS — it only exists in the local-only (non-API) code path.
  // The bridge overrides saveAdminPassword() to use the API, so this line only runs in
  // legacy mode. Guard prevents a ReferenceError crash if the bridge is somehow bypassed.
  if (typeof ADMIN_USERS !== 'undefined' && Array.isArray(ADMIN_USERS) && ADMIN_USERS[idx]) {
    ADMIN_USERS[idx].passHash = hash;
  }
  APP.tenant = tenants[tIdx];
  closeModal();
  toast('Password updated', 'success');
}

// Hash change
window.addEventListener('hashchange', () => {
  if (!APP.loggedIn) return;
  const hash = window.location.hash.replace('#', '');
  if (APP.role === 'admin' && hash && PAGES.find(p => p.id === hash) && hash !== APP.page) navigate(hash);
});

